import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Table.module.css';

type TableSize = 'sm' | 'md' | 'lg';
type TableVariant = 'line' | 'outline';

type TableRootProps = HTMLArkProps<'table'> & {
  interactive?: boolean;
  showColumnBorder?: boolean;
  size?: TableSize;
  stickyHeader?: boolean;
  striped?: boolean;
  variant?: TableVariant;
};

type TableScrollAreaProps = HTMLArkProps<'div'>;
type TableCaptionProps = HTMLArkProps<'caption'> & {
  side?: 'top' | 'bottom';
};
type TableColumnGroupProps = HTMLArkProps<'colgroup'>;
type TableColumnProps = HTMLArkProps<'col'> & {
  htmlWidth?: string | number;
};
type TableHeaderProps = HTMLArkProps<'thead'>;
type TableBodyProps = HTMLArkProps<'tbody'>;
type TableFooterProps = HTMLArkProps<'tfoot'>;
type TableRowProps = HTMLArkProps<'tr'>;
type TableColumnHeaderProps = HTMLArkProps<'th'> & {
  numeric?: boolean;
};
type TableCellProps = HTMLArkProps<'td'> & {
  numeric?: boolean;
};
type TableEmptyProps = HTMLArkProps<'td'> & {
  colSpan: number;
};

const TableRoot = forwardRef<HTMLTableElement, TableRootProps>(function TableRoot(
  {
    asChild,
    className,
    interactive = false,
    showColumnBorder = false,
    size = 'md',
    stickyHeader = false,
    striped = false,
    variant = 'line',
    ...props
  },
  ref,
) {
  return (
    <ark.table
      ref={ref}
      asChild={asChild}
      data-scope="table"
      data-part="root"
      data-slot="table-root"
      data-interactive={interactive || undefined}
      data-show-column-border={showColumnBorder || undefined}
      data-size={size}
      data-sticky-header={stickyHeader || undefined}
      data-striped={striped || undefined}
      data-variant={variant}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const TableScrollArea = forwardRef<HTMLDivElement, TableScrollAreaProps>(function TableScrollArea(
  { asChild, className, ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      asChild={asChild}
      data-scope="table"
      data-part="scroll-area"
      data-slot="table-scroll-area"
      className={clsx(styles.scrollArea, normalizeClassName(className))}
      {...props}
    />
  );
});

const TableCaption = forwardRef<HTMLTableCaptionElement, TableCaptionProps>(function TableCaption(
  { asChild, className, side = 'bottom', ...props },
  ref,
) {
  return (
    <ark.caption
      ref={ref}
      asChild={asChild}
      data-scope="table"
      data-part="caption"
      data-side={side}
      data-slot="table-caption"
      className={clsx(styles.caption, normalizeClassName(className))}
      {...props}
    />
  );
});

const TableColumnGroup = forwardRef<HTMLTableColElement, TableColumnGroupProps>(
  function TableColumnGroup({ asChild, className, ...props }, ref) {
    return (
      <ark.colgroup
        ref={ref}
        asChild={asChild}
        data-scope="table"
        data-part="column-group"
        data-slot="table-column-group"
        className={normalizeClassName(className)}
        {...props}
      />
    );
  },
);

const TableColumn = forwardRef<HTMLTableColElement, TableColumnProps>(function TableColumn(
  { asChild, className, htmlWidth, width, ...props },
  ref,
) {
  return (
    <ark.col
      ref={ref}
      asChild={asChild}
      data-scope="table"
      data-part="column"
      data-slot="table-column"
      width={htmlWidth ?? width}
      className={normalizeClassName(className)}
      {...props}
    />
  );
});

const TableHeader = forwardRef<HTMLTableSectionElement, TableHeaderProps>(function TableHeader(
  { asChild, className, ...props },
  ref,
) {
  return (
    <ark.thead
      ref={ref}
      asChild={asChild}
      data-scope="table"
      data-part="header"
      data-slot="table-header"
      className={clsx(styles.header, normalizeClassName(className))}
      {...props}
    />
  );
});

const TableBody = forwardRef<HTMLTableSectionElement, TableBodyProps>(function TableBody(
  { asChild, className, ...props },
  ref,
) {
  return (
    <ark.tbody
      ref={ref}
      asChild={asChild}
      data-scope="table"
      data-part="body"
      data-slot="table-body"
      className={clsx(styles.body, normalizeClassName(className))}
      {...props}
    />
  );
});

const TableFooter = forwardRef<HTMLTableSectionElement, TableFooterProps>(function TableFooter(
  { asChild, className, ...props },
  ref,
) {
  return (
    <ark.tfoot
      ref={ref}
      asChild={asChild}
      data-scope="table"
      data-part="footer"
      data-slot="table-footer"
      className={clsx(styles.footer, normalizeClassName(className))}
      {...props}
    />
  );
});

const TableRow = forwardRef<HTMLTableRowElement, TableRowProps>(function TableRow(
  { asChild, className, ...props },
  ref,
) {
  return (
    <ark.tr
      ref={ref}
      asChild={asChild}
      data-scope="table"
      data-part="row"
      data-slot="table-row"
      className={clsx(styles.row, normalizeClassName(className))}
      {...props}
    />
  );
});

const TableColumnHeader = forwardRef<HTMLTableCellElement, TableColumnHeaderProps>(
  function TableColumnHeader({ asChild, className, numeric = false, ...props }, ref) {
    return (
      <ark.th
        ref={ref}
        asChild={asChild}
        data-scope="table"
        data-part="column-header"
        data-numeric={numeric || undefined}
        data-slot="table-column-header"
        className={clsx(
          styles.columnHeader,
          numeric && styles.numeric,
          normalizeClassName(className),
        )}
        {...props}
      />
    );
  },
);

const TableCell = forwardRef<HTMLTableCellElement, TableCellProps>(function TableCell(
  { asChild, className, numeric = false, ...props },
  ref,
) {
  return (
    <ark.td
      ref={ref}
      asChild={asChild}
      data-scope="table"
      data-part="cell"
      data-numeric={numeric || undefined}
      data-slot="table-cell"
      className={clsx(styles.cell, numeric && styles.numeric, normalizeClassName(className))}
      {...props}
    />
  );
});

const TableEmpty = forwardRef<HTMLTableCellElement, TableEmptyProps>(function TableEmpty(
  { asChild, children = 'No results.', className, colSpan, ...props },
  ref,
) {
  return (
    <ark.tr
      data-scope="table"
      data-part="row"
      data-slot="table-row"
      className={clsx(styles.row, styles.emptyRow)}
    >
      <ark.td
        ref={ref}
        asChild={asChild}
        data-scope="table"
        data-part="empty"
        data-slot="table-empty"
        colSpan={colSpan}
        className={clsx(styles.cell, styles.empty, normalizeClassName(className))}
        {...props}
      >
        {children}
      </ark.td>
    </ark.tr>
  );
});

const Table = Object.assign(TableRoot, {
  Root: TableRoot,
  ScrollArea: TableScrollArea,
  Caption: TableCaption,
  ColumnGroup: TableColumnGroup,
  Column: TableColumn,
  Header: TableHeader,
  Body: TableBody,
  Footer: TableFooter,
  Row: TableRow,
  ColumnHeader: TableColumnHeader,
  Cell: TableCell,
  Empty: TableEmpty,
});

export { Table };
export type {
  TableBodyProps,
  TableCaptionProps,
  TableCellProps,
  TableColumnGroupProps,
  TableColumnHeaderProps,
  TableColumnProps,
  TableEmptyProps,
  TableFooterProps,
  TableHeaderProps,
  TableRootProps,
  TableRowProps,
  TableScrollAreaProps,
  TableSize,
  TableVariant,
};

@layer ui.components {
  .scrollArea {
    box-sizing: border-box;
    position: relative;
    width: 100%;
    min-width: 0;
    overflow-x: auto;
    isolation: isolate;
    border: var(--table-scroll-area-border-width, var(--table-border-width, var(--border-width-sm)))
      solid var(--table-scroll-area-border-color, var(--table-border-color, var(--color-border)));
    border-radius: var(--table-scroll-area-radius, var(--radius-lg));
    background-color: var(--table-scroll-area-bg, var(--color-card));
    box-shadow: var(--table-scroll-area-shadow, none);
  }

  .root {
    --table-cell-padding-x-default: var(--table-cell-padding-x, var(--spacing-4));
    --table-cell-padding-y-default: var(--table-cell-padding-y, var(--spacing-3));
    --table-empty-padding-y-default: calc(var(--table-cell-padding-y-default) * 2);

    box-sizing: border-box;
    width: 100%;
    border-collapse: collapse;
    border-spacing: 0;
    color: var(--table-color, var(--color-foreground));
    font-family: var(--table-font-family, inherit);
    font-size: var(--table-font-size, var(--text-sm));
    line-height: var(--table-line-height, var(--line-height-text-sm));
    text-align: left;
    isolation: isolate;

    &[data-size='sm'] {
      --table-cell-padding-x-default: var(--table-cell-padding-x, var(--spacing-3));
      --table-cell-padding-y-default: var(--table-cell-padding-y, var(--spacing-2));
      font-size: var(--table-font-size-sm, var(--text-xs));
      line-height: var(--table-line-height-sm, var(--line-height-text-xs));
    }

    &[data-size='lg'] {
      --table-cell-padding-x-default: var(--table-cell-padding-x, var(--spacing-5));
      --table-cell-padding-y-default: var(--table-cell-padding-y, var(--spacing-4));
      font-size: var(--table-font-size-lg, var(--text-md));
      line-height: var(--table-line-height-lg, var(--line-height-text-md));
    }

    &[data-variant='outline'] {
      border: var(--table-border-width, var(--border-width-sm)) solid
        var(--table-border-color, var(--color-border));
    }
  }

  .caption {
    box-sizing: border-box;
    color: var(--table-caption-color, var(--color-muted-foreground));
    font-size: var(--table-caption-font-size, var(--text-sm));
    line-height: var(--table-caption-line-height, var(--line-height-text-sm));
    padding-inline: var(--table-caption-padding-x, var(--table-cell-padding-x-default));
    text-align: left;
    text-wrap: pretty;

    &[data-side='top'] {
      caption-side: top;
      padding-block: var(--table-caption-padding-edge, var(--spacing-2))
        var(--table-caption-padding-y, var(--spacing-3));
    }

    &[data-side='bottom'] {
      caption-side: bottom;
      padding-block: var(--table-caption-padding-y, var(--spacing-3))
        var(--table-caption-padding-edge, var(--spacing-2));
    }
  }

  .row {
    transition: var(--table-row-transition, background-color var(--transition-default));
  }

  .header .row,
  .body .row {
    border-bottom: var(--table-border-width, var(--border-width-sm)) solid
      var(--table-border-color, var(--color-border));
  }

  .root[data-interactive] .body .row:hover {
    background-color: var(--table-row-bg-hover, var(--color-muted));
  }

  .root[data-striped] .body .row:nth-child(even):not(.emptyRow):not(:hover) {
    background-color: var(
      --table-row-bg-striped,
      color-mix(in oklab, var(--color-muted) 35%, transparent)
    );
  }

  .root[data-show-column-border] :is(.columnHeader, .cell):not(:last-child) {
    border-inline-end: var(
        --table-column-border-width,
        var(--table-border-width, var(--border-width-sm))
      )
      solid var(--table-column-border-color, var(--table-border-color, var(--color-border)));
  }

  .root[data-sticky-header] .header {
    position: sticky;
    inset-block-start: 0;
    z-index: var(--table-sticky-header-z-index, 3);
    background-color: var(--table-sticky-header-bg, var(--table-scroll-area-bg, var(--color-card)));
  }

  .body .row:last-child {
    border-bottom: 0;
  }

  .footer {
    border-top: var(--table-border-width, var(--border-width-sm)) solid
      var(--table-border-color, var(--color-border));
    background-color: var(--table-footer-bg, var(--color-muted));
    color: var(--table-footer-color, var(--table-color, var(--color-foreground)));
    font-weight: var(--table-footer-font-weight, var(--weight-medium));
  }

  .columnHeader,
  .cell {
    position: relative;
    z-index: 0;
    padding-block: var(--table-cell-padding-y-default);
    padding-inline: var(--table-cell-padding-x-default);
    vertical-align: middle;

    &[data-sticky='start'] {
      position: sticky;
      inset-inline-start: 0;
      z-index: var(--table-sticky-column-z-index, 2);
      background-color: var(
        --table-sticky-column-bg,
        var(--table-scroll-area-bg, var(--color-card))
      );
    }

    &[data-sticky='end'] {
      position: sticky;
      inset-inline-end: 0;
      z-index: var(--table-sticky-column-z-index, 2);
      background-color: var(
        --table-sticky-column-bg,
        var(--table-scroll-area-bg, var(--color-card))
      );
    }
  }

  .root[data-sticky-header] .header .columnHeader[data-sticky] {
    z-index: var(--table-sticky-intersection-z-index, 4);
  }

  .columnHeader {
    color: var(--table-column-header-color, var(--color-muted-foreground));
    font-weight: var(--table-column-header-font-weight, var(--weight-medium));
    text-align: inherit;
    white-space: nowrap;
  }

  .cell {
    color: inherit;
  }

  .numeric {
    text-align: right;
    white-space: nowrap;
    font-variant-numeric: tabular-nums;
  }

  .emptyRow:hover {
    background-color: transparent;
  }

  .empty {
    padding-block: var(--table-empty-padding-y, var(--table-empty-padding-y-default));
    color: var(--table-empty-color, var(--color-muted-foreground));
    text-align: center;
  }
}
